mapper.select:
SELECT log_id, requested_by, request_type, input_data_json, prediction_result_json, created_at
FROM ai_prediction_log


    (request_type LIKE CONCAT('%',#{q},'%')
     OR input_data_json LIKE CONCAT('%',#{q},'%'))

   AND created_at >= #{from} 
     AND created_at <= #{to}   

ORDER BY created_at DESC
LIMIT #{limit}
